  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  // NOTE: When using mysql or sqlserver, uncomment the @db.Text annotations in model Account below\n  // Further reading:\n  // https://next-auth.js.org/adapters/prisma#create-the-prisma-schema\n  // https://www.prisma.io/docs/reference/api-reference/prisma-schema-reference#string\n  url      = env(\"DATABASE_URL\")\n}\n\n// ===== AUTHENTICATION MODELS =====\n// Necessary for NextAuth\nmodel Account {\n  id                       String  @id @default(cuid())\n  userId                   String\n  type                     String\n  provider                 String\n  providerAccountId        String\n  refresh_token            String? @db.Text\n  access_token             String? // @db.Text\n  expires_at               Int?\n  token_type               String?\n  scope                    String?\n  id_token                 String? // @db.Text\n  session_state            String?\n  user                     User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  refresh_token_expires_in Int?\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\n// ===== USER MODEL =====\nmodel User {\n  id            String    @id @default(cuid())\n  name          String?\n  email         String?   @unique\n  emailVerified DateTime?\n  image         String?\n\n  // Auth relations\n  accounts Account[]\n  sessions Session[]\n\n  // E-commerce relations\n  cart   Cart?\n  orders Order[]\n\n  // Address relations\n  homeAddress    Address?  @relation(\"HomeAddress\", fields: [homeAddressId], references: [id])\n  homeAddressId  String?   @unique\n  otherAddresses Address[] @relation(\"OtherAddresses\")\n}\n\n// ===== PRODUCT CATALOG MODELS =====\nmodel Category {\n  id          String    @id @default(cuid())\n  name        String\n  description String\n  slug        String    @unique\n  products    Product[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([slug])\n}\n\nmodel Brand {\n  id          String    @id @default(cuid())\n  name        String\n  description String\n  slug        String    @unique\n  products    Product[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([slug])\n}\n\nmodel Product {\n  id          String           @id @default(cuid())\n  name        String\n  description String\n  slug        String           @unique\n  variants    ProductVariant[]\n\n  brand      Brand    @relation(fields: [brandId], references: [id])\n  brandId    String\n  category   Category @relation(fields: [categoryId], references: [id])\n  categoryId String\n\n  createdAt     DateTime       @default(now())\n  updatedAt     DateTime       @updatedAt\n  productImages ProductImage[]\n\n  isFeatured Boolean @default(false)\n  isActive   Boolean @default(false)\n\n  @@index([slug])\n  @@index([categoryId])\n  @@index([brandId])\n}\n\nmodel ProductVariant {\n  id    String  @id @default(cuid())\n  price Decimal @db.Decimal(10, 2)\n  stock Int     @default(0)\n\n  product       Product               @relation(fields: [productId], references: [id], onDelete: Cascade)\n  productId     String\n  cartProducts  CartProduct[]\n  orderItems    OrderItem[]\n  variantImages ProductVariantImage[]\n\n  color String?\n  size  Size    @default(ONE_SIZE)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([productId])\n}\n\nmodel ProductImage {\n  id      String  @id @default(cuid())\n  url     String\n  altText String?\n\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  productId String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([productId])\n}\n\nmodel ProductVariantImage {\n  id      String  @id @default(cuid())\n  url     String\n  altText String?\n\n  productVariant   ProductVariant @relation(fields: [productVariantId], references: [id], onDelete: Cascade)\n  productVariantId String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([productVariantId])\n}\n\n// ===== SHOPPING CART MODELS =====\nmodel Cart {\n  id       String        @id @default(cuid())\n  user     User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId   String        @unique\n  products CartProduct[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel CartProduct {\n  id       String @id @default(cuid())\n  quantity Int    @default(1)\n\n  cart             Cart           @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  cartId           String\n  productVariant   ProductVariant @relation(fields: [productVariantId], references: [id])\n  productVariantId String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([cartId, productVariantId])\n  @@index([cartId])\n  @@index([productVariantId])\n}\n\nenum Size {\n  XXXXS\n  XXXS\n  XXS\n  XS\n  S\n  M\n  L\n  XL\n  XXL\n  XXXL\n  XXXXL\n  ONE_SIZE\n}\n\n// ===== ORDER MODELS =====\nenum OrderStatus {\n  PENDING\n  DELIVERING\n  COMPLETED\n  CANCELLED\n  RETURNING\n  RETURNED\n}\n\nmodel Order {\n  id         String      @id @default(cuid())\n  status     OrderStatus @default(PENDING)\n  total      Decimal     @db.Decimal(10, 2)\n  orderItems OrderItem[]\n\n  user      User    @relation(fields: [userId], references: [id])\n  userId    String\n  address   Address @relation(fields: [addressId], references: [id])\n  addressId String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([addressId])\n  @@index([status])\n}\n\nmodel OrderItem {\n  id       String  @id @default(cuid())\n  quantity Int     @default(1)\n  price    Decimal @db.Decimal(10, 2) // Price at time of purchase (frozen)\n\n  order            Order          @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  orderId          String\n  productVariant   ProductVariant @relation(fields: [productVariantId], references: [id])\n  productVariantId String\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime? @default(now())\n\n  @@index([orderId])\n  @@index([productVariantId])\n}\n\n// ===== ADDRESS MODEL =====\nmodel Address {\n  id         String @id @default(cuid())\n  street     String\n  city       String\n  state      String\n  postalCode String\n  country    String\n\n  // Relations\n  orders             Order[]\n  userHomeAddress    User?   @relation(\"HomeAddress\")\n  userOtherAddresses User?   @relation(\"OtherAddresses\", fields: [userId], references: [id])\n  userId             String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n}\n",
